// Simple bucket access check - bucket already exists, just verify we can access it
export const checkApplicationsBucket = async (): Promise<boolean> => {
  try {
    const { error } = await supabase.storage
      .from('applications')
      .list('', { limit: 1 });
    return !error;
  } catch {
    return false;
  }
};

// Alias for backward compatibility
export const createApplicationsBucketIfNotExists = checkApplicationsBucket;

// User roles management - now uses server-side user_roles table and RLS policies
export type UserRole = 'user' | 'admin';

export const getUserRole = async (): Promise<UserRole> => {
  try {
    const { data: sessionData } = await supabase.auth.getSession();
    if (!sessionData.session) {
      return 'user';
    }
    
    const { data, error } = await supabase.rpc('has_role', {
      _user_id: sessionData.session.user.id,
      _role: 'admin'
    });
    
    if (error) {
      console.error('Error checking user role:', error);
      return 'user';
    }
    
    return data === true ? 'admin' : 'user';
  } catch (error) {
    console.error('Error determining user role:', error);
    return 'user';
  }
};
